import { useContext } from 'react';

import { annotationsOverlay } from './AnnotationsOverlays.sty.js';
import { MARGIN_TOP_STROKE } from '../../constants.js';
import { AnnotationsConfigContext } from '../../contexts/AnnotationsConfig.context.js';
import { useOverlayEvents } from '../../hooks/useOverlayEvents.js';

export type AnnotationsOverlaysProps = {
  height: number;
};

export const AnnotationsOverlays = ({ height }: AnnotationsOverlaysProps) => {
  const { labelsWidth, trackWidth } = useContext(AnnotationsConfigContext);

  const { handleMouseMove, handleMouseLeave, handleClick } = useOverlayEvents();

  return (
    <div
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
      onClick={handleClick}
      className={annotationsOverlay}
      style={{
        height,
        width: trackWidth,
        left: labelsWidth,
        top: MARGIN_TOP_STROKE,
      }}
    />
  );
};
